int bdb_direct_count(bdb_cursor_ifn_t *cur, int ixnum, int64_t *rcnt, int is_snapcur, uint32_t modsnap_start_lsn_file, uint32_t modsnap_start_lsn_offset, uint32_t last_checkpoint_lsn_file, uint32_t last_checkpoint_lsn_offset)
{
    int64_t count = 0;
    int parallel_count;
    bdb_state_type *state = cur->impl->state;
    DB **db;
    int stripes;
    pthread_attr_t attr;
    if (ixnum < 0) { // data
        db = state->dbp_data[0];
        stripes = state->attr->dtastripe;
        parallel_count = gbl_parallel_count;
        Pthread_attr_init(&attr);
#ifdef PTHREAD_STACK_MIN
        Pthread_attr_setstacksize(&attr, PTHREAD_STACK_MIN + 512 * 1024);
#endif
    } else { // index
        db = &state->dbp_ix[ixnum];
        stripes = 1;
        parallel_count = 0;
    }
    struct count_arg args[stripes];
    pthread_t thds[stripes];
    for (int i = 0; i < stripes; ++i) {
        args[i].db = db[i];
        args[i].is_snapcur = is_snapcur;
        args[i].modsnap_start_lsn.file = modsnap_start_lsn_file;
        args[i].modsnap_start_lsn.offset = modsnap_start_lsn_offset;
        args[i].last_checkpoint_lsn.file = last_checkpoint_lsn_file;
        args[i].last_checkpoint_lsn.offset = last_checkpoint_lsn_offset;
        if (parallel_count) {
            args[i].sqlthd = pthread_getspecific(query_info_key);
            Pthread_create(&thds[i], &attr, db_count, &args[i]);
        } else {
            args[i].sqlthd = NULL;
            db_count(&args[i]);
        }
    }
    int rc = 0;
    void *ret;
    for (int i = 0; i < stripes; ++i) {
        if (parallel_count) {
            pthread_join(thds[i], &ret);
        }

        if (rc != 0) /* We're just waiting for all threads to exit. */
            continue;

        if (args[i].rc == DB_LOCK_DEADLOCK) {
            rc = BDBERR_DEADLOCK;
        } else if (args[i].rc != DB_NOTFOUND) {
            rc = -1;
        }
        count += args[i].count;
    }
    if (parallel_count) {
        Pthread_attr_destroy(&attr);
    }
    if (rc == 0) *rcnt = count;
    return rc;
}

