    v.data = alloca(128 * 1024);
    v.ulen = 128 * 1024;
    v.flags = DB_DBT_USERMEM;

    DB *db = arg->db;
    DBC *dbc;
    if ((rc = db->cursor(db, NULL, &dbc, 0)) != 0) {
        arg->rc = rc;
        return NULL;
    }
    if (arg->is_snapcur) {
        dbc->flags |= DBC_SNAPSHOT; 
        dbc->modsnap_start_lsn = arg->modsnap_start_lsn;
        dbc->last_checkpoint_lsn = arg->last_checkpoint_lsn;
    }
